package com.umograd.content.unit;import com.umograd.content.application.dto.QuestionDto;import com.umograd.content.application.dto.TaskContentDto;import com.umograd.content.application.dto.TaskDto;import com.umograd.content.application.task.command.CreateTaskCommand;import com.umograd.content.application.task.command.CreateTaskHandler;import com.umograd.content.domain.task.*;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import java.time.LocalDateTime;import java.util.List;import static org.junit.jupiter.api.Assertions.assertEquals;import static org.junit.jupiter.api.Assertions.assertNotNull;import static org.mockito.ArgumentMatchers.any;import static org.mockito.Mockito.when;@ExtendWith(MockitoExtension.class)class CreateTaskHandlerTest {    @Mock    private TaskRepository taskRepository;    @InjectMocks    private CreateTaskHandler createTaskHandler;    @Test    void shouldCreateTask() {        QuestionDto questionDto = new QuestionDto(                "MULTIPLE_CHOICE",                "Что лишнее?",                List.of("Круг", "Квадрат", "Треугольник"), "Круг",                null        );        CreateTaskCommand command = new CreateTaskCommand(                "Логическая задача",                "Найди лишнее",                "MODERATOR",                 6, 10,                "EASY",                new TaskContentDto(List.of(questionDto)));        Question question = new Question(                "MULTIPLE_CHOICE",                "Что лишнее?",                List.of("Круг", "Квадрат", "Треугольник"), "Круг",                null        );        Task mockTask = Task.createNew(                new TaskId(1L),                null,                new TaskTitle("Логическая задача"),                new TaskDescription("Найди лишнее"),                "MODERATOR",                LocalDateTime.now(),                new AgeRange(6, 10),                Difficulty.EASY,                new TaskContent(List.of(question))        );        when(taskRepository.save(any(Task.class))).thenReturn(mockTask);        TaskDto result = createTaskHandler.handle(command);        assertNotNull(result);        assertEquals("Логическая задача", result.title());    }}